# Build the final JSON structure according to citations_validation schema.
def aya_ref(name, num, aya):
    return {"sura_name": name, "sura_number": num, "aya_number": aya}

citations_output = []
for q in quotes_list:
    entry = {
        "span_start": q["span_start"],
        "span_end": q["span_end"],
        "span_text": q["span_text"],
        "citation_type": "Aya" if q["type"]=="Aya" else "Hadeeth",
        "is_valid": False,
        "aya_reference": {},
        "hadeeth_reference": {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    }
    if q["type"]=="Aya":
        # Determine which ayah based on content heuristically
        st = q["span_text"]
        if "يَعْقِلُونَ" in st or "افلم" in st or "أفلم" in st:
            # Surah al-Hajj 22:46
            entry["aya_reference"] = aya_ref("الحج", 22, 46)
        elif "وَمَا أُوتِيتُم" in st or "أوتيتم" in st:
            entry["aya_reference"] = aya_ref("الإسراء", 17, 85)
        elif "يَعْلَمُ مَنْ خَلَقَ" in st or "من خلق" in st:
            entry["aya_reference"] = aya_ref("الملك", 67, 14)
        elif "قُلْ أَأَنتُمْ" in st or "أأنتم" in st:
            entry["aya_reference"] = aya_ref("البقرة", 2, 140)
        else:
            # Unknown, leave empty
            pass
    else:
        # Hadeeth: leave reference empty (insufficient data)
        pass
    citations_output.append(entry)

json.dumps({"citations": citations_output}, ensure_ascii=False, indent=2)[:1500]

